37:     const swiftc = b.addSystemCommand(&.{
38:         "swiftc",
39:         "app/main.swift",
40:         "-import-objc-header",
41:         "include/bridging-header.h",
42:     });
43:     swiftc.addPrefixedDirectoryArg("-L", lib.getEmittedBinDirectory());
44:     swiftc.addArgs(&.{"-lminimal"});
