1: const State = enum(u8) {
2:     idle,
3:     one_a,
4:     circumflex,
5:     literal,
6: };
7: 
8: pub const ProcessKeyEventResult = extern struct {
9:     num_backspaces: u8,
10:     num_chars: u8,
11:     swallow_event: bool,
12:     chars: [*]const u16,
13: };
14: 
15: var state: State = .idle;
16: var first_a_upper: bool = false;
17: var gap: u8 = 0;
18: 
19: var bufs: [2][2]u16 = .{ .{ 0, 0 }, .{ 0, 0 } };
20: var active: u1 = 0;
21: 
22: const passthrough: ProcessKeyEventResult = .{
23:     .num_backspaces = 0,
24:     .num_chars = 0,
25:     .swallow_event = false,
26:     .chars = @ptrCast(&bufs[0]),
27: };
28: 
29: fn emit(num_backspaces: u8, chars: []const u16) ProcessKeyEventResult {
30:     const buf = @as([*]u16, @ptrCast(&bufs[active]));
31:     for (chars, 0..) |c, i| buf[i] = c;
32:     active ^= 1;
33:     return .{
34:         .num_backspaces = num_backspaces,
35:         .num_chars = @intCast(chars.len),
36:         .swallow_event = true,
37:         .chars = buf,
38:     };
39: }
40: 
41: fn isA(c: u16) bool {
42:     return c == 'a' or c == 'A';
43: }
44: 
45: fn isAlphanumeric(c: u16) bool {
46:     return (c >= '0' and c <= '9') or
47:         (c >= 'A' and c <= 'Z') or
48:         (c >= 'a' and c <= 'z');
49: }
50: 
51: export fn reset_state() void {
52:     state = .idle;
53:     first_a_upper = false;
54:     gap = 0;
55: }
56: 
57: export fn process_backspace() ProcessKeyEventResult {
58:     if (gap > 0) {
59:         gap -= 1;
60:     } else switch (state) {
61:         .literal => state = .one_a,
62:         .idle => {},
63:         else => reset_state(),
64:     }
65:     return passthrough;
66: }
67: 
68: export fn process_key_event(char_code: u16) ProcessKeyEventResult {
69:     if (isA(char_code)) {
70:         if (gap == 0 and state != .literal) return handleA(char_code);
71:     } else if (!isAlphanumeric(char_code)) {
72:         reset_state();
73:         return passthrough;
74:     } else if (state == .idle) {
75:         return passthrough;
76:     }
77: 
78:     if (gap >= 255) {
79:         reset_state();
80:         return passthrough;
81:     }
82:     gap += 1;
83:     return passthrough;
84: }
85: 
86: fn handleA(char_code: u16) ProcessKeyEventResult {
87:     const upper = char_code == 'A';
88:     switch (state) {
89:         .idle => {
90:             state = .one_a;
91:             first_a_upper = upper;
92:             return passthrough;
93:         },
94:         .one_a => {
95:             state = .circumflex;
96:             const c: u16 = if (first_a_upper) 0x00C2 else 0x00E2;
97:             return emit(1, &.{c});
98:         },
99:         .circumflex => {
100:             state = .literal;
101:             const c0: u16 = if (first_a_upper) 'A' else 'a';
102:             const c1: u16 = if (upper) 'A' else 'a';
103:             return emit(1, &.{ c0, c1 });
104:         },
105:         .literal => unreachable,
106:     }
107: }

